import os
from typing import Optional

# 从环境变量获取 Gmail 凭据
GMAIL_USER = os.environ.get("GMAIL_USER", "")
GMAIL_PASSWORD = os.environ.get("GMAIL_APP_PASSWORD", "")  # 需要使用 Gmail 应用专用密码

def check_gmail_inbox() -> dict:
    """
    轮询 Gmail 收件箱，返回未读邮件信息。

    返回格式:
    {
        "success": bool,
        "unread_count": int,
        "recent_emails": list[dict],
        "error": Optional[str]
    }
    """
    if not GMAIL_USER or not GMAIL_PASSWORD:
        return {
            "success": False,
            "unread_count": 0,
            "recent_emails": [],
            "error": "缺少 Gmail 凭据，请设置环境变量 GMAIL_USER 和 GMAIL_APP_PASSWORD"
        }

    try:
        # 连接 Gmail IMAP 服务器
        mail = imaplib.IMAP4_SSL("imap.gmail.com")
        mail.login(GMAIL_USER, GMAIL_PASSWORD)
        mail.select("inbox")

        # 搜索未读邮件
        status, messages = mail.search(None, "UNSEEN")

        if status != "OK":
            mail.logout()
            return {
                "success": False,
                "unread_count": 0,
                "recent_emails": [],
                "error": "搜索邮件失败"
            }

        unread_ids = messages[0].split() if messages[0] else []
        unread_count = len(unread_ids)

        # 只获取最近的 10 封未读邮件详情（避免一次性拉取太多）
        recent_emails = []
        for msg_id in unread_ids[-10:]:
            status, msg_data = mail.fetch(msg_id, "(RFC822)")
            if status != "OK":
                continue

            raw_email = msg_data[0][1]
            msg = email.message_from_bytes(raw_email)

            # 提取邮件基本信息
            email_info = {
                "id": msg_id.decode(),
                "subject": msg.get("Subject", "(无主题)"),
                "from": msg.get("From", "(未知发件人)"),
                "date": str(parsedate_to_datetime(msg.get("Date")) if msg.get("Date") else "未知"),
                "snippet": ""
            }

            # 提取邮件正文前100字符作为摘要
            if msg.is_multipart():
                for part in msg.walk():
                    if part.get_content_type() == "text/plain":
                        payload = part.get_payload(decode=True)
                        if payload:
                            try:
                                text = payload.decode("utf-8")[:100]
                                email_info["snippet"] = text
                            except:
                                pass
                        break
            else:
                payload = msg.get_payload(decode=True)
                if payload:
                    try:
                        text = payload.decode("utf-8")[:100]
                        email_info["snippet"] = text
                    except:
                        pass

            recent_emails.append(email_info)

        mail.logout()

        return {
            "success": True,
            "unread_count": unread_count,
            "recent_emails": recent_emails,
            "checked_at": datetime.now().isoformat(),
            "error": None
        }

    except imaplib.IMAP4.error as e:
        return {
            "success": False,
            "unread_count": 0,
            "recent_emails": [],
            "error": f"IMAP 连接失败: {str(e)}"
        }
    except Exception as e:
        return {
            "success": False,
            "unread_count": 0,
            "recent_emails": [],
            "error": f"未知错误: {str(e)}"
        }
"}

