import email
from email.header import decode_header
import os
import logging
from datetime import datetime
from typing import Optional

logger = logging.getLogger(__name__)

# ============================================================
# 配置说明（请设置以下环境变量）：
#   GMAIL_ADDRESS       — 你的 Gmail 邮箱地址
#   GMAIL_APP_PASSWORD  — Google 应用专用密码（需在 Google 账号安全设置中生成）
# ============================================================

def _decode_mime_header(header_value: str) -> str:
    """解码邮件标题"""
    if header_value is None:
        return ""
    decoded_parts = decode_header(header_value)
    result = []
    for part, encoding in decoded_parts:
        if isinstance(part, bytes):
            try:
                result.append(part.decode(encoding or "utf-8", errors="replace"))
            except (LookupError, UnicodeDecodeError):
                result.append(part.decode("utf-8", errors="replace"))
        else:
            result.append(part)
    return "".join(result)


def check_gmail_inbox(
    email_address: Optional[str] = None,
    app_password: Optional[str] = None,
    max_emails: int = 5,
) -> dict:
    """
    连接 Gmail IMAP，检查收件箱中未读邮件（UNSEEN），
    返回新邮件数量及每封邮件的摘要信息。

    Args:
        email_address: 邮箱地址，默认从环境变量 GMAIL_ADDRESS 读取
        app_password:  应用专用密码，默认从环境变量 GMAIL_APP_PASSWORD 读取
        max_emails:    最多返回多少封邮件的摘要，默认 5 封

    Returns:
        dict 包含:
            - success: bool
            - total_unread: int      — 未读邮件总数
            - new_emails: list[dict] — 最新的 max_emails 封未读邮件摘要
            - checked_at: str       — 检查时间戳
            - error: str (可选)     — 出错时的错误信息
    """
    addr = email_address or os.environ.get("GMAIL_ADDRESS")
    pwd = app_password or os.environ.get("GMAIL_APP_PASSWORD")

    if not addr or not pwd:
        return {
            "success": False,
            "error": "缺少邮箱配置。请设置环境变量 GMAIL_ADDRESS 和 GMAIL_APP_PASSWORD，或在调用时传入 email_address 和 app_password。",
        }

    try:
        # 连接 Gmail IMAP SSL
        mail = imaplib.IMAP4_SSL("imap.gmail.com")
        mail.login(addr, pwd)
        mail.select("INBOX")

        # 搜索未读邮件
        status, messages = mail.search(None, "UNSEEN")
        if status != "OK":
            return {"success": False, "error": "搜索邮件失败"}

        email_ids = messages[0].split() if messages[0] else []
        total_unread = len(email_ids)
        logger.info(f"Gmail 收件箱未读邮件数: {total_unread}")

        new_emails = []
        # 只取最新的 max_emails 封
        for eid in email_ids[-max_emails:]:
            status, msg_data = mail.fetch(eid, "(RFC822)")
            if status != "OK":
                continue

            for part in msg_data:
                if isinstance(part, tuple):
                    msg = email.message_from_bytes(part[1])

                    subject = _decode_mime_header(msg.get("Subject"))
                    sender = _decode_mime_header(msg.get("From"))
                    date_str = msg.get("Date", "")

                    # 提取邮件正文前 200 字作为预览
                    body_preview = ""
                    if msg.is_multipart():
                        for payload in msg.walk():
                            if payload.get_content_type() == "text/plain":
                                try:
                                    body_preview = payload.get_payload(decode=True).decode("utf-8", errors="replace")[:200]
                                except Exception:
                                    body_preview = "[无法解码正文]"
                                break
                    else:
                        try:
                            body_preview = msg.get_payload(decode=True).decode("utf-8", errors="replace")[:200]
                        except Exception:
                            body_preview = "[无法解码正文]"

                    new_emails.append({
                        "subject": subject,
                        "sender": sender,
                        "date": date_str,
                        "body_preview": body_preview,
                    })

        mail.logout()

        return {
            "success": True,
            "total_unread": total_unread,
            "new_emails": new_emails,
            "checked_at": datetime.utcnow().isoformat() + "Z",
        }

    except imaplib.IMAP4.error as e:
        return {"success": False, "error": f"IMAP 认证失败，请检查邮箱地址和应用专用密码: {str(e)}"}
    except Exception as e:
        logger.exception("检查 Gmail 收件箱时出错")
        return {"success": False, "error": f"发生未知错误: {str(e)}"}
"}
